+        // Split multiple statements
+        const statements = processedSql
+            .split(';')
+            .map(s => s.trim())
+            .filter(s => s.length > 0);
+
+        const results = [];
+
+        for (const stmt of statements) {
+            try {
+                const lexer = new SQLLexer(stmt);
+                const tokens = lexer.tokenize();
+                const parser = new SQLParser(tokens);
+                const ast = parser.parse();
