+        return this;
+    }
+
+    /**
+     * Register a custom aggregate function (stub for compatibility)
+     * @param {string} name - Function name
+     * @param {Object} funcs - Aggregate functions {init, step, finalize}
+     * @returns {Database} this
+     */
