+    /**
+     * Format a value for SQL
+     */
+    _formatValue(val) {
+        if (val === null || val === undefined) {
+            return 'NULL';
+        }
+        if (typeof val === 'string') {
+            return `'${val.replace(/'/g, "''")}'`;
+        }
+        if (typeof val === 'number') {
+            return String(val);
+        }
+        if (typeof val === 'boolean') {
+            return val ? 'TRUE' : 'FALSE';
+        }
+        if (Array.isArray(val)) {
+            // Vector
+            return `'[${val.join(',')}]'`;
+        }
+        return String(val);
+    }
