+/**
+ * Initialize LanceQL with sql.js-compatible API
+ *
+ * Drop-in replacement for initSqlJs():
+ *
+ * @example
+ * // sql.js style
+ * import initSqlJs from 'sql.js';
+ * const SQL = await initSqlJs();
+ * const db = new SQL.Database();
+ *
+ * // LanceQL replacement
+ * import { initSqlJs } from 'lanceql';
+ * const SQL = await initSqlJs();
